import { Segment } from '../src/core/segment';

describe('ChronoBase Core Engine', () => {
  it('should store and query data points using binary search', () => {
    const segment = new Segment("test_seg");
    const startTime = 1000;

    // Add 10 points
    for (let i = 0; i < 10; i++) {
      segment.add({
        timestamp: startTime + (i * 10),
        value: i,
        tags: {}
      });
    }

    segment.seal();

    // Query middle range
    const results = segment.query({ start: 1025, end: 1055 });

    // Should return timestamps: 1030, 1040, 1050
    expect(results.length).toBe(3);
    expect(results[0].timestamp).toBe(1030);
    expect(results[2].timestamp).toBe(1050);
  });

  it('should be immutable after sealing', () => {
    const segment = new Segment("read_only_test");
    segment.seal();
    expect(() => segment.add({ timestamp: 1, value: 1, tags: {} })).toThrow();
  });
});

