import { DataPoint, QueryRange } from './types.js';

/**
 * Segment represents an immutable block of time-series data.
 * In a real-world scenario, this would be backed by an SSTable or similar.
 */
export class Segment {
  private points: DataPoint[] = [];
  private isReadOnly: boolean = false;

  constructor(public readonly id: string) {}

  /**
   * Adds a data point to the segment. 
   * Points MUST be added in chronological order to maintain O(log n) search.
   */
  public add(point: DataPoint): void {
    if (this.isReadOnly) {
      throw new Error("Cannot add to a read-only segment");
    }

    // In a production engine, we would validate order here
    this.points.push(point);
  }

  /**
   * Seals the segment, making it immutable.
   */
  public seal(): void {
    this.isReadOnly = true;
    // Sort just in case, though ingest should handle it
    this.points.sort((a, b) => a.timestamp - b.timestamp);
  }

  /**
   * Performs a binary search for the first point >= start.
   * Time Complexity: O(log n)
   */
  public query(range: QueryRange): DataPoint[] {
    const startIndex = this.binarySearch(range.start);
    const result: DataPoint[] = [];

    for (let i = startIndex; i < this.points.length; i++) {
      if (this.points[i].timestamp > range.end) break;
      result.push(this.points[i]);
    }

    return result;
  }

  private binarySearch(target: number): number {
    let low = 0;
    let high = this.points.length;

    while (low < high) {
      const mid = Math.floor((low + high) / 2);
      if (this.points[mid].timestamp < target) {
        low = mid + 1;
      } else {
        high = mid;
      }
    }
    return low;
  }

  public get size(): number {
    return this.points.length;
  }
}

