/* ══════════════════════════════════════════
   ANIMATED CIRCADIAN CLOCK (SVG)
══════════════════════════════════════════ */
function CircadianClock({ activeDrug }) {
  const [tick, setTick] = useState(0);
  useEffect(() => {
    const id = setInterval(() => setTick(t => (t + 1) % 240), 150);
    return () => clearInterval(id);
  }, []);

  const R = 130, cx = 160, cy = 160;
  const hourAngle = (h) => (h / 24) * 2 * Math.PI - Math.PI / 2;
  const polar = (h, r) => ({
    x: cx + r * Math.cos(hourAngle(h)),
    y: cy + r * Math.sin(hourAngle(h)),
  });

  const handH = (tick / 240) * 24;
  const handPt = polar(handH, R * 0.72);

  const segments = Array.from({ length: 24 }, (_, i) => {
    const a1 = hourAngle(i), a2 = hourAngle(i + 1);
    const ro = R + 18, ri = R + 2;
    const x1 = cx + ri * Math.cos(a1), y1 = cy + ri * Math.sin(a1);
    const x2 = cx + ro * Math.cos(a1), y2 = cy + ro * Math.sin(a1);
    const x3 = cx + ro * Math.cos(a2), y3 = cy + ro * Math.sin(a2);
    const x4 = cx + ri * Math.cos(a2), y4 = cy + ri * Math.sin(a2);
    const peak = activeDrug ? TARGETS.find(t => t.id === activeDrug)?.zt_max ?? -1 : -1;
    const ztH = [0,4,8,12,16,20];
    const nearest = ztH.reduce((a,b) => Math.abs(b-i)<Math.abs(a-i)?b:a, ztH[0]);
    let fill = "#0D1626";
    if (peak >= 0 && Math.abs(nearest - peak) <= 2) fill = "#00C896";
    else if (i >= 6 && i <= 8) fill = "#1e3a5f";
    else if (i >= 14 && i <= 17) fill = "#1e3a5f";
    return (
      <path key={i} d={`M${x1},${y1} L${x2},${y2} A${ro},${ro} 0 0,1 ${x3},${y3} L${x4},${y4} A${ri},${ri} 0 0,0 ${x1},${y1}`}
        fill={fill} stroke="#0A0E1A" strokeWidth="0.5" opacity="0.95" />
    );
  });

  const drugs = TARGETS.filter(t => t.drug !== "—").slice(0, 8);

  return (
    <svg viewBox="0 0 320 320" style={{ width:"100%", maxWidth:340 }}>
      <defs>
        <radialGradient id="bg_grad" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor="#0D1E38" />
          <stop offset="100%" stopColor="#050B17" />
        </radialGradient>
        <filter id="glow">
          <feGaussianBlur stdDeviation="2.5" result="blur"/>
          <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
        <filter id="handglow">
          <feGaussianBlur stdDeviation="3" result="blur"/>
          <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>

      <circle cx={cx} cy={cy} r={R+22} fill="url(#bg_grad)" />
      {segments}

      {/* Hour ticks */}
      {Array.from({length:24},(_,i)=>{
        const p1=polar(i,R-2), p2=polar(i,R-10);
        return <line key={i} x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke="#1E3A5F" strokeWidth="1"/>;
      })}

      {/* ZT labels */}
      {[0,4,8,12,16,20].map(h=>{
        const p=polar(h,R-20); const labels=["ZT0","ZT4","ZT8","ZT12","ZT16","ZT20"];
        return <text key={h} x={p.x} y={p.y} fill="#6B8CC4" fontSize="7" textAnchor="middle" dominantBaseline="middle" fontFamily="JetBrains Mono">{labels[h/4]}</text>;
      })}

      {/* Inner glow circle */}
      <circle cx={cx} cy={cy} r={R-28} fill="#050B17" stroke="#0D2040" strokeWidth="1"/>
      <circle cx={cx} cy={cy} r={R-30} fill="none" stroke="#00C896" strokeWidth="0.5" opacity="0.3"/>

      {/* Drug dot markers */}
      {drugs.map((t,i)=>{
        const p=polar(t.zt_max, R-44);
        const isActive = activeDrug === t.id;
        return (
          <g key={t.id} filter={isActive?"url(#glow)":""}>
            <circle cx={p.x} cy={p.y} r={isActive?5:3} fill={isActive?"#00C896":"#1D4ED8"}
              stroke={isActive?"#00C896":"#2563EB"} strokeWidth="1" opacity={isActive?1:0.7}/>
          </g>
        );
      })}

      {/* Sweeping hand */}
      <line x1={cx} y1={cy} x2={handPt.x} y2={handPt.y}
        stroke="#00C896" strokeWidth="1.5" strokeLinecap="round" filter="url(#handglow)" opacity="0.9"/>
      <circle cx={cx} cy={cy} r={3} fill="#00C896" filter="url(#glow)"/>

      {/* Center label */}
      <text x={cx} y={cy-10} fill="#E8EDF5" fontSize="9" textAnchor="middle" fontFamily="Syne" fontWeight="700">CHRONO</text>
      <text x={cx} y={cy+4} fill="#00C896" fontSize="9" textAnchor="middle" fontFamily="Syne" fontWeight="700">BASE</text>
      <text x={cx} y={cy+16} fill="#6B8CC4" fontSize="6" textAnchor="middle" fontFamily="JetBrains Mono">24h · 15 targets</text>
    </svg>
  );
}

