    <div style={{ fontFamily:"JetBrains Mono, monospace" }}>
      <div style={{ overflowX:"auto" }}>
        {/* Column headers */}
        <div style={{ display:"grid", gridTemplateColumns:"130px repeat(6,1fr)", gap:3, marginBottom:4 }}>
          <div/>
          {ZT_CLOCKS.map((z,i)=>(
            <div key={i} style={{ textAlign:"center", padding:"6px 0" }}>
              <div style={{ color:"#00C896", fontSize:10, fontWeight:500 }}>{["ZT0","ZT4","ZT8","ZT12","ZT16","ZT20"][i]}</div>
              <div style={{ color:"#4B6A9B", fontSize:9 }}>{z}</div>
            </div>
          ))}
        </div>

        {/* Rows */}
        {TARGETS.map((t,ri)=>{
          const isSelected = selectedTarget === t.id;
          return (
            <div key={t.id} style={{ display:"grid", gridTemplateColumns:"130px repeat(6,1fr)", gap:3, marginBottom:3,
              borderRadius:6, background: isSelected ? "#0D1E38" : "transparent",
              outline: isSelected ? "1px solid #00C896" : "none", cursor:"pointer" }}
              onClick={()=>setSelectedTarget(isSelected ? null : t.id)}>
              <div style={{ display:"flex", flexDirection:"column", justifyContent:"center", paddingLeft:6, paddingRight:8 }}>
                <div style={{ color:"#E8EDF5", fontSize:11, fontWeight:500 }}>{t.label}</div>
                <div style={{ color:"#4B6A9B", fontSize:9, marginTop:1 }}>{t.drug}</div>
              </div>
              {t.score.map((s,ci)=>{
                const c = scoreColor(s);
                const isHov = hovered?.r===ri && hovered?.c===ci;
