function ChronoPocketAtlas() {
  const [hovered, setHovered] = useState(null);
  const [selectedTarget, setSelectedTarget] = useState(null);

  return (
    <div style={{ fontFamily:"JetBrains Mono, monospace" }}>
      <div style={{ overflowX:"auto" }}>
        {/* Column headers */}
        <div style={{ display:"grid", gridTemplateColumns:"130px repeat(6,1fr)", gap:3, marginBottom:4 }}>
          <div/>
          {ZT_CLOCKS.map((z,i)=>(
            <div key={i} style={{ textAlign:"center", padding:"6px 0" }}>
              <div style={{ color:"#00C896", fontSize:10, fontWeight:500 }}>{["ZT0","ZT4","ZT8","ZT12","ZT16","ZT20"][i]}</div>
              <div style={{ color:"#4B6A9B", fontSize:9 }}>{z}</div>
            </div>
          ))}
        </div>

        {/* Rows */}
        {TARGETS.map((t,ri)=>{
          const isSelected = selectedTarget === t.id;
          return (
            <div key={t.id} style={{ display:"grid", gridTemplateColumns:"130px repeat(6,1fr)", gap:3, marginBottom:3,
              borderRadius:6, background: isSelected ? "#0D1E38" : "transparent",
              outline: isSelected ? "1px solid #00C896" : "none", cursor:"pointer" }}
              onClick={()=>setSelectedTarget(isSelected ? null : t.id)}>
              <div style={{ display:"flex", flexDirection:"column", justifyContent:"center", paddingLeft:6, paddingRight:8 }}>
                <div style={{ color:"#E8EDF5", fontSize:11, fontWeight:500 }}>{t.label}</div>
                <div style={{ color:"#4B6A9B", fontSize:9, marginTop:1 }}>{t.drug}</div>
              </div>
              {t.score.map((s,ci)=>{
                const c = scoreColor(s);
                const isHov = hovered?.r===ri && hovered?.c===ci;
                const isOptimal = ci === t.score.indexOf(Math.max(...t.score));
                return (
                  <div key={ci}
                    onMouseEnter={()=>setHovered({r:ri,c:ci,s,target:t.label,zt:ZT_CLOCKS[ci],drug:t.drug})}
                    onMouseLeave={()=>setHovered(null)}
                    style={{ background:c.bg, borderRadius:5, padding:"8px 4px", textAlign:"center",
                      border: isOptimal ? "1.5px solid #00C896" : isHov ? "1px solid #3B82F6" : "1px solid transparent",
                      transition:"all .15s", transform: isHov ? "scale(1.05)" : "scale(1)",
                      boxShadow: isOptimal ? "0 0 8px #00C89650" : "none" }}>
                    <div style={{ color:c.text, fontSize:10, fontWeight:500 }}>{s.toFixed(2)}</div>
                  </div>
                );
              })}
            </div>
          );
        })}
      </div>

      {/* Tooltip */}
      {hovered && (
        <div style={{ marginTop:12, background:"#0D1E38", border:"1px solid #1E3A5F", borderRadius:8,
          padding:"10px 14px", fontSize:11, color:"#E8EDF5" }}>
          <span style={{ color:"#00C896", fontWeight:600 }}>{hovered.target}</span>
          {" · "}<span style={{ color:"#F59E0B" }}>{ZT_LABELS[Object.values(hovered).indexOf(hovered.zt) >= 0 ? ZT_CLOCKS.indexOf(hovered.zt) : 0]?.split("\n")[0]}</span>
          {" at "}<span style={{ color:"#94a3b8" }}>{hovered.zt}</span>
          {" → Druggability: "}<span style={{ color: hovered.s >= 0.75 ? "#00C896" : hovered.s >= 0.50 ? "#F59E0B" : "#6B7A99", fontWeight:600 }}>{hovered.s.toFixed(3)}</span>
          {hovered.drug !== "—" && <span style={{ color:"#4B6A9B" }}> · Drug: {hovered.drug}</span>}
        </div>
      )}

      {/* Legend */}
      <div style={{ display:"flex", gap:16, marginTop:12, alignItems:"center", flexWrap:"wrap" }}>
        <span style={{ color:"#4B6A9B", fontSize:10 }}>Druggability score:</span>
        {[["≥0.78","#00C896","Optimal"],["0.60–0.77","#0D9488","Good"],["0.45–0.59","#1D4ED8","Moderate"],["<0.45","#1E293B","Low"]].map(([l,c,d])=>(
          <div key={l} style={{ display:"flex", alignItems:"center", gap:5 }}>
            <div style={{ width:12, height:12, borderRadius:3, background:c }}/>
            <span style={{ color:"#6B8CC4", fontSize:10 }}>{d} ({l})</span>
          </div>
        ))}
        <div style={{ display:"flex", alignItems:"center", gap:5 }}>
          <div style={{ width:12, height:12, borderRadius:3, border:"1.5px solid #00C896", background:"transparent" }}/>
          <span style={{ color:"#6B8CC4", fontSize:10 }}>Optimal ZT for target</span>
        </div>
      </div>
    </div>
  );
}

