/**
 * Cosinor Engine: Performs least-squares fitting of circadian data.
 * Solves: Y(t) = M + beta*cos(wt) + gamma*sin(wt)
 */

export interface CosinorResult {
  mesor: number;
  amplitude: number;
  acrophase: number; // In radians
  zt_peak: number;   // Peak time in ZT hours (0-24)
  p_value: number;   // Statistical significance
}

export class CosinorEngine {
  private static readonly OMEGA = (2 * Math.PI) / 24;

  /**
   * Fits a 6-point circadian dataset using the 3x3 normal equations and Cramer's Rule.
   * @param timestamps Array of ZT hours (e.g., [0, 4, 8, 12, 16, 20])
   * @param values Array of observed values (e.g., pocket volumes or druggability scores)
   */
  public static fit(timestamps: number[], values: number[]): CosinorResult {
    if (timestamps.length !== values.length) throw new Error("Input arrays must have same length");

    let sumY = 0, sumC = 0, sumS = 0;
    let sumCC = 0, sumSS = 0, sumCS = 0;
    let sumYC = 0, sumYS = 0;
    const n = timestamps.length;

    for (let i = 0; i < n; i++) {
      const t = timestamps[i]!;
      const v = values[i]!;
      const c = Math.cos(this.OMEGA * t);
      const s = Math.sin(this.OMEGA * t);

      sumY += v;
      sumC += c;
      sumS += s;
      sumCC += c * c;
      sumSS += s * s;
      sumCS += c * s;
      sumYC += v * c;
      sumYS += v * s;
    }

    // Matrix: [ n     sumC   sumS  ] [ M ]   [ sumY  ]
    //         [ sumC  sumCC  sumCS ] [ B ] = [ sumYC ]
    //         [ sumS  sumCS  sumSS ] [ G ]   [ sumYS ]

    const detMain = this.determinant3x3(
      n, sumC, sumS,
      sumC, sumCC, sumCS,
      sumS, sumCS, sumSS
    );

    const detM = this.determinant3x3(
      sumY, sumC, sumS,
      sumYC, sumCC, sumCS,
      sumYS, sumCS, sumSS
    );

    const detB = this.determinant3x3(
      n, sumY, sumS,
      sumC, sumYC, sumCS,
      sumS, sumYS, sumSS
    );

    const detG = this.determinant3x3(
      n, sumC, sumY,
      sumC, sumCC, sumYC,
      sumS, sumCS, sumYS
    );

    const M = detM / detMain;
    const beta = detB / detMain;
    const gamma = detG / detMain;

    const amplitude = Math.sqrt(beta * beta + gamma * gamma);
    let acrophase = Math.atan2(-gamma, beta);

    // Convert acrophase to ZT peak hour
    let zt_peak = (-acrophase / this.OMEGA);
    if (zt_peak < 0) zt_peak += 24;
    if (zt_peak >= 24) zt_peak -= 24;

    // Simplified p-value calculation (F-test proxy for demo)
    // In production, this would use the residuals and degrees of freedom
    const p_value = amplitude > (M * 0.1) ? 0.001 : 0.5; 

    return {
      mesor: M,
      amplitude: amplitude,
      acrophase: acrophase,
      zt_peak: zt_peak,
      p_value: p_value
    };
  }

  private static determinant3x3(
    a: number, b: number, c: number,
    d: number, e: number, f: number,
    g: number, h: number, i: number
  ): number {
    return a * (e * i - f * h) - b * (d * i - f * g) + c * (d * h - e * g);
  }
}

