import { Segment } from './core/segment.js';
import { CosinorEngine } from './core/math/cosinor.js';

async function bootstrap() {
  console.log("🕰️ ChronoBase Scientific Engine v1.0");

  // Example Target: FGFR4 (Hepatocellular Carcinoma)
  // Data from ChronoBase Documentation
  const target = {
    id: "FGFR4",
    drug: "Fisogatinib",
    zt_points: [0, 4, 8, 12, 16, 20],
    scores: [0.40, 0.58, 0.85, 0.75, 0.47, 0.33] // Pocket druggability scores
  };

  console.log(`\n🔍 Analyzing Target: ${target.id} (${target.drug})`);

  // 1. Perform Cosinor Fitting
  const fit = CosinorEngine.fit(target.zt_points, target.scores);

  console.log("📊 Cosinor Fit Results:");
  console.log(`   - MESOR:     ${fit.mesor.toFixed(3)}`);
  console.log(`   - Amplitude: ${fit.amplitude.toFixed(3)}`);
  console.log(`   - Acrophase: ZT ${fit.zt_peak.toFixed(1)}`);
  console.log(`   - P-Value:   ${fit.p_value.toFixed(4)} ${fit.p_value < 0.05 ? '✓ (Significant)' : '✗ (Non-Rhythmic)'}`);

  // 2. Determine Optimal Dosing Window
  const windowStart = (fit.zt_peak - 1 + 24) % 24;
  const windowEnd = (fit.zt_peak + 1) % 24;

  console.log(`\n💊 Clinical Recommendation for ${target.drug}:`);
  console.log(`   Optimal Dosing Window: ZT ${windowStart.toFixed(1)} – ZT ${windowEnd.toFixed(1)}`);
  console.log(`   (Reason: Peak pocket accessibility at ZT ${fit.zt_peak.toFixed(1)})`);

  // 3. Store in ChronoBase Storage Segment
  const segment = new Segment("analysis_batch_2026_06");
  target.zt_points.forEach((zt, i) => {
    segment.add({
      timestamp: zt,
      value: target.scores[i] || 0,
      tags: { target: target.id, type: "druggability" }
    });
  });
  segment.seal();
  console.log(`\n✅ Results stored in segment ${segment.id}.`);
}

bootstrap().catch(console.error);

