import { Segment } from './core/segment.js';
import type { DataPoint } from './core/types.js';

async function bootstrap() {
  console.log("🚀 Initializing ChronoBase Core Engine...");

  const segment = new Segment("seg_001");

  // Simulate data ingestion
  console.log("📥 Ingesting data points...");
  const now = Date.now();
  for (let i = 0; i < 1000; i++) {
    segment.add({
      timestamp: now + (i * 1000),
      value: Math.random() * 100,
      tags: { sensorId: "temp_01", location: "datacenter_1" }
    });
  }

  segment.seal();
  console.log(`✅ Segment sealed. Size: ${segment.size} points.`);

  // Test query
  const queryRange = {
    start: now + 5000,
    end: now + 10000
  };

  console.log(`🔍 Querying range: ${queryRange.start} to ${queryRange.end}`);
  const results = segment.query(queryRange);
