import { CosinorEngine } from './core/math/cosinor.js';

function generateAsciiChart() {
  const target = {
    id: "FGFR4",
    zt_points: [0, 4, 8, 12, 16, 20],
    scores: [0.40, 0.58, 0.85, 0.75, 0.47, 0.33]
  };

  const fit = CosinorEngine.fit(target.zt_points, target.scores);
  const OMEGA = (2 * Math.PI) / 24;

  console.log(`\n📈 Circadian Druggability Curve: ${target.id}`);
  console.log(`   Peak Accessibility at ZT ${fit.zt_peak.toFixed(1)}\n`);

  const height = 10;
  const width = 48; // 2 hours per character
  const chart: string[][] = Array.from({ length: height }, () => Array(width).fill(' '));

  // Draw Y-axis
  for (let y = 0; y < height; y++) chart[y]![0] = '│';

  // Plot the fitted curve
  for (let x = 0; x < width; x++) {
    const t = (x / width) * 24;
    const val = fit.mesor + fit.amplitude * Math.cos(OMEGA * t + fit.acrophase);

    // Normalize value to height (0.2 to 0.9 range roughly)
    const normVal = (val - 0.2) / 0.8;
    const y = Math.max(0, Math.min(height - 1, Math.round(normVal * (height - 1))));
    chart[(height - 1) - y]![x] = '●';
  }

  // Draw X-axis
  console.log("   Druggability");
  chart.forEach((row, i) => {
    const label = (0.2 + ((height - 1 - i) / (height - 1)) * 0.8).toFixed(1);
    console.log(`${label} ${row.join('')}`);
  });
  console.log("       └" + "─".repeat(width-1));
  console.log("        ZT0     ZT4     ZT8     ZT12    ZT16    ZT20    ZT24");

  console.log(`\n🎯 OPTIMAL DOSING WINDOW: ZT ${fit.zt_peak.toFixed(1)} (± 1h)`);
}

generateAsciiChart();

