import { KineticsEngine } from './core/math/kinetics.js';

function visualizeKinetics() {
  console.log("🧪 ChronoBase Kinetics Analysis: Kinase vs. Phosphorylation (P(t))");

  // Model CK1e kinase (peaks ~ZT20) driving PER2 phosphorylation
  const result = KineticsEngine.solve(0.4, 0.15, 20);

  console.log(`\n⚙️ Parameters: k_on=0.4, k_off=0.15, Kinase Peak=ZT20`);
  console.log(`⏱️ Resulting Phase Lag: ${result.lag_hours.toFixed(1)} hours`);

  const height = 12;
  const width = 60;
  const chart: string[][] = Array.from({ length: height }, () => Array(width).fill(' '));

  // Plotting two curves: 
  // 'k' = Kinase Activity
  // 'P' = Phosphorylation Fraction
  for (let x = 0; x < width; x++) {
    const idx = Math.floor((x / width) * result.zt_points.length);
    const kVal = result.kinase_activity[idx] || 0;
    const pVal = result.phosphorylation[idx] || 0;

    const ky = Math.round(kVal * (height - 1));
    const py = Math.round(pVal * (height - 1));

    chart[(height - 1) - ky]![x] = 'k';
    chart[(height - 1) - py]![x] = 'P';

    // Intersection
    if (ky === py) chart[(height - 1) - ky]![x] = 'X';
  }

  console.log("\nFraction (0-1)");
  chart.forEach((row, i) => {
    const label = ((height - 1 - i) / (height - 1)).toFixed(1);
    console.log(`${label} │ ${row.join('')}`);
  });
  console.log("    └" + "─".repeat(width));
  console.log("      ZT0         ZT6         ZT12        ZT18        ZT24");

  console.log("\nLegend: k = Kinase activity, P = Phosphorylation P(t), X = Overlap");
  console.log("Observation: Phosphorylation (P) lags behind Kinase (k) due to ODE integration.");
}

visualizeKinetics();

