export class KineticsEngine {
  /**
   * Solves the PTM kinetics using the Euler method for a 24h cycle.
   * @param k_on Association rate constant
   * @param k_off Dissociation rate constant
   * @param kinase_peak_zt The ZT hour when kinase concentration peaks
   */
  public static solve(
    k_on: number = 0.5, 
    k_off: number = 0.2, 
    kinase_peak_zt: number = 4
  ): KineticsResult {
    const dt = 0.1; // 6 minute steps
    const steps = 24 / dt;
    const OMEGA = (2 * Math.PI) / 24;
    const phase_offset = -kinase_peak_zt * OMEGA;

    let p = 0.2; // Initial phosphorylation fraction
    const result: KineticsResult = {
      zt_points: [],
      kinase_activity: [],
      phosphorylation: [],
      accessibility: [],
      lag_hours: 0
    };

    // Run for 48 hours to reach steady state, only record last 24h
    for (let step = 0; step < steps * 2; step++) {
      const t = step * dt;
      const zt = t % 24;

      // Kinase activity K(t) modeled as a sinusoid (0 to 1)
      const k_t = 0.5 * (1 + Math.cos(OMEGA * zt + phase_offset));

      // dP/dt
      const dp = (k_on * k_t * (1 - p)) - (k_off * p);
      p += dp * dt;

      if (step >= steps) {
        result.zt_points.push(zt);
        result.kinase_activity.push(k_t);
        result.phosphorylation.push(p);
        // Accessibility is inversely proportional to phosphorylation for many targets
        result.accessibility.push(1 - p);
      }
    }

    // Calculate lag between Kinase peak and Phosphorylation peak
    const kMaxIdx = result.kinase_activity.indexOf(Math.max(...result.kinase_activity));
    const pMaxIdx = result.phosphorylation.indexOf(Math.max(...result.phosphorylation));
    result.lag_hours = (pMaxIdx - kMaxIdx) * dt;

    return result;
  }
}

