  /**
   * Solves the PTM kinetics using the 4th-order Runge-Kutta (RK4) method.
   * RK4 provides O(dt^4) precision, far superior to the Euler method.
   */
  public static solve(
    k_on: number = 0.5, 
    k_off: number = 0.2, 
    kinase_peak_zt: number = 4
  ): KineticsResult {
    const dt = 0.1; 
    const steps = 24 / dt;
    const OMEGA = (2 * Math.PI) / 24;
    const phase_offset = -kinase_peak_zt * OMEGA;

    let p = 0.2; 
    const result: KineticsResult = {
      zt_points: [],
      kinase_activity: [],
      phosphorylation: [],
      accessibility: [],
      lag_hours: 0
    };

    // Helper to calculate dP/dt at any given ZT and P value
    const deriv = (zt: number, p_val: number): number => {
      const k_t = 0.5 * (1 + Math.cos(OMEGA * zt + phase_offset));
      return (k_on * k_t * (1 - p_val)) - (k_off * p_val);
    };

    // Run for 48 hours to reach steady state
    for (let step = 0; step < steps * 2; step++) {
      const t = step * dt;
      const zt = t % 24;

      // RK4 Steps
      const k1 = deriv(zt, p);
      const k2 = deriv(zt + dt/2, p + (dt*k1)/2);
      const k3 = deriv(zt + dt/2, p + (dt*k2)/2);
      const k4 = deriv(zt + dt, p + dt*k3);

      p += (dt / 6) * (k1 + 2*k2 + 2*k3 + k4);

      if (step >= steps) {
        result.zt_points.push(zt);
        result.kinase_activity.push(0.5 * (1 + Math.cos(OMEGA * zt + phase_offset)));
        result.phosphorylation.push(p);
        result.accessibility.push(1 - p);
      }
    }

    const kMaxIdx = result.kinase_activity.indexOf(Math.max(...result.kinase_activity));
    const pMaxIdx = result.phosphorylation.indexOf(Math.max(...result.phosphorylation));
    result.lag_hours = (pMaxIdx - kMaxIdx) * dt;

    return result;
  }
}

